    // Dilate matrix (using host-side functions for simplicity)
    int *newMatrix_host = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    for (int i = 0; i < IszX * IszY * Nfr; ++i) newMatrix_host[i] = 0;

    int radius_dilate = 5;
    for (int z = 0; z < Nfr; z++) {
        for (int x = 0; x < IszX; x++) {
            for (int y = 0; y < IszY; y++) {
                if (I_host[x * IszY * Nfr + y * Nfr + z] == 1) {
                    // Dilate_matrix (host-side)
                    int startX = max(0, x - radius_dilate);
                    int startY = max(0, y - radius_dilate);
                    int endX = min(IszX, x + radius_dilate);
                    int endY = min(IszY, y + radius_dilate);

                    for (int cur_x = startX; cur_x < endX; ++cur_x) {
                        for (int cur_y = startY; cur_y < endY; ++cur_y) {
                            double distance = sqrt(pow((double)(cur_x - x), 2) + pow((double)(cur_y - y), 2));
                            if (distance < radius_dilate) {
                                newMatrix_host[cur_x * IszY * Nfr + cur_y * Nfr + z] = 1;
                            }
                        }
                    }
                }
            }
        }
    }
    memcpy(I_host, newMatrix_host, sizeof(int) * IszX * IszY * Nfr);
    free(newMatrix_host);

    // Define background, add noise (using host-side functions)
    // setIf
    int testValue = 0, newValue = 100;
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int z = 0; z < Nfr; z++) {
                if (I_host[x * IszY * Nfr + y * Nfr + z] == testValue)
                    I_host[x * IszY * Nfr + y * Nfr + z] = newValue;
            }
        }
    }
    testValue = 1, newValue = 228;
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int z = 0; z < Nfr; z++) {
                if (I_host[x * IszY * Nfr + y * Nfr + z] == testValue)
                    I_host[x * IszY * Nfr + y * Nfr + z] = newValue;
            }
        }
    }

    // addNoise
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int z = 0; z < Nfr; z++) {
                I_host[x * IszY * Nfr + y * Nfr + z] = I_host[x * IszY * Nfr + y * Nfr + z] + (int)(5 * randn_device(seed_host, 0)); // Using host seed for now
            }
        }
    }

    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start_time, endVideoSequence));

    // Call particle filter on CUDA device
    particleFilter(I_host, IszX, IszY, Nfr, seed_host, Nparticles);

    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start_time, endParticleFilter));

    free(I_host);
    free(seed_host);

    return 0;
}
